mapper.select:
SELECT id, case_name, rule_id, rule_name_snapshot, last_result, last_output, last_run_time, crte_time, updt_time
FROM rule_test_case ORDER BY crte_time DESC, id DESC
LIMIT #{offset}, #{pageSize}

mapper.update:
UPDATE rule_test_case
SET case_name = #{caseName}, rule_id = #{ruleId}, rule_name_snapshot = #{ruleNameSnapshot}, updt_time = NOW()
WHERE id = #{id}

UPDATE rule_test_case
SET last_result = #{lastResult}, last_output = #{lastOutput}, last_run_time = #{lastRunTime}, updt_time = NOW()
WHERE id = #{id}
